{
  "schema": "brainflow.procedural_guideline.v1",
  "name": "cli_arg_length_guard",
  "goal": "Reduce Windows CLI arg-length risk",
  "rules": [
    "Prefer file-based payloads over inline CLI arguments for long text or JSON",
    "If content > 8KB, write to a temp file and pass the file path",
    "Avoid embedding large JSON in command-line flags; use @file or stdin",
    "When possible, compress or shorten prompts before execution"
  ],
  "thresholds": {
    "inline_arg_soft_limit_bytes": 8192,
    "inline_arg_hard_limit_bytes": 16384
  }
}
